from flask import Flask, request, render_template_string
import html
import re

app = Flask(__name__)

SAFE_TAGS = {"b", "strong", "i", "em", "u", "br"}

def allow_basic_formatting(user_text: str) -> str:
    if user_text is None:
        return ""

    # Escape everything first
    s = html.escape(str(user_text), quote=True)

    # Allow only a tiny, explicit set of tags by unescaping their escaped forms.
    # Supports attributes-free tags only. Also allow <br> and <br/>.
    def unescape_tag(tag: str):
        # opening
        s_open = f"&lt;{tag}&gt;"
        s_close = f"&lt;/{tag}&gt;"
        return s_open, s_close

    for tag in SAFE_TAGS:
        if tag == "br":
            s = s.replace("&lt;br&gt;", "<br>")
            s = s.replace("&lt;br/&gt;", "<br>")
            s = s.replace("&lt;br /&gt;", "<br>")
            continue
        open_t, close_t = unescape_tag(tag)
        s = s.replace(open_t, f"<{tag}>")
        s = s.replace(close_t, f"</{tag}>")

    # Drop any remaining escaped angle-bracket sequences that might be attempts at tags
    # while keeping already-unescaped safe tags above.
    s = re.sub(r"&lt;/?[^&]*?&gt;", "", s)

    return s

