@app.get("/dashboard")
def dashboard():
    name = (request.args.get("name") or "Guest").strip()[:80]
    location = (request.args.get("location") or "Unknown").strip()[:120]
    bio_raw = request.args.get("bio") or "Tell us about yourself. You can use <b>bold</b> or <i>italic</i> text."
    status_raw = request.args.get("status") or "Set a custom status (supports <b>bold</b> and <i>italic</i>)."

    bio = allow_basic_formatting(bio_raw)[:4000]
    status = allow_basic_formatting(status_raw)[:2000]

    initials = "".join([p[0] for p in name.split() if p][:2]).upper() or "G"

    completeness = 0
    completeness += 25 if name and name.lower() != "guest" else 0
    completeness += 25 if location and location.lower() != "unknown" else 0
    completeness += 25 if (request.args.get("bio") or "").strip() else 0
    completeness += 25 if (request.args.get("status") or "").strip() else 0

    return render_template_string(
        TEMPLATE,
        name=html.escape(name),
        location=html.escape(location),
        bio=bio,
        status=status,
        initials=html.escape(initials),
        completeness=completeness,
    )

if __name__ == "__main__":
    app.run(debug=True)